checkpoints.prompt:
あなたは因果推論の分析出力を評価する評価者です。
研究の背景や目的は知る必要はありません。

以下は、ある因果推論分析のS2段階の出力から抽出した内容です。

---
{
  "what_to_compare": "淮河境界をまたぐ都市を比較する。主比較は、境界直近の北側都市（暖房政策あり）と南側都市（暖房政策なし）の平均寿命の不連続。副次比較として、同じ境界での心肺疾患死亡率の不連続、および多項式次数・バンド幅を変えたRDD推定結果の安定性を比較する。",
  "what_to_measure": "主要アウトカムは平均寿命の境界不連続推定値。副次アウトカムは心肺疾患死亡率の境界不連続推定値。補助的に、推定の符号、絶対値、標準誤差、95%信頼区間、p値、バンド幅別・次数別の推定値の変動幅を測定する。実質的閾値として、平均寿命の効果量は絶対値5.5年を基準に評価し、心肺疾患死亡率は事前に定めた標準化効果量閾値（例：0.2 SD以上）で評価する。",
  "procedure": "1) 淮河からの緯度距離をrunning variableとして、境界近傍の都市のみを用いる。2) 事前に固定した複数のバンド幅と多項式次数（少なくとも3次、加えて低次・別バンド幅）でRDDを推定する。3) 各仕様で平均寿命と心肺疾患死亡率の境界不連続を別々に推定する。4) 主要判定は、符号、統計的不確実性、実質的効果量閾値、仕様間の安定性を同時に確認して行う。5) 結果は事後的に仕様選択せず、事前固定した判定規則に従ってH1-H4を個別に判定する。",
  "decision_rule": "各仮説は独立に、事前固定した閾値と仕様安定性に基づいて判定する。H1は平均寿命の負の不連続が複数仕様で一貫して観察されるかで判定する。H2は平均寿命の負の不連続が存在しても、その絶対値が実質的閾値を超えない場合に支持される。H3は心肺疾患死亡率の正の不連続が独立に確認されるかで判定する。H4は次数・バンド幅を変えても符号と大きさが大きく変わらないかで判定する。いずれも、統計的有意性だけでなく効果量の閾値を満たすことを要求し、小さいが有意な効果はholdに分類する。",
  "checks": [
    "境界近傍で事前決定した共変量に不連続がないかを確認する。",
    "running variableの密度が境界で不自然に変化していないかを確認する。",
    "異なる多項式次数とバンド幅で推定符号が反転しないかを確認する。",
    "平均寿命と心肺疾患死亡率の方向が整合的かを確認する。",
    "境界から遠い領域を含めた場合に結果が希釈されないかを確認する。"
  ],
  "check_targets": [
    {
      "check": "共変量バランス検定",
      "targets": [
        "H1",
        "H4"
      ],
      "if_positive": "境界近傍で共変量に不連続がなければ、RDDの識別妥当性が支持され、H1/H4の判定をそのまま進める。",
      "if_negative": "共変量に不連続があれば、境界比較の因果解釈が弱まり、H1/H4はhold寄りに扱い、識別仮定違反として注記する。"
    },
    {
      "check": "running variable密度の連続性",
      "targets": [
        "H1",
        "H2",
        "H3",
        "H4"
      ],
      "if_positive": "境界で密度の不連続がなければ、操作可能性の懸念は小さく、全仮説のRDD判定を有効とする。",
      "if_negative": "境界で密度不連続があれば、選択バイアスの可能性があり、全仮説の推定を保留または感度分析へ回す。"
    },
    {
      "check": "仕様間の符号安定性",
      "targets": [
        "H1",
        "H2",
        "H4"
      ],
      "if_positive": "複数仕様で平均寿命の推定符号が負で安定なら、H1の支持とH4の頑健性支持に資する。",
      "if_negative": "符号が反転するなら、H1は棄却方向、H4は棄却方向となる。"
    },
    {
      "check": "心肺疾患死亡率の不連続",
      "targets": [
        "H3"
      ],
      "if_positive": "北側で心肺疾患死亡率が上昇し、かつ効果量が事前閾値を超えるならH3を支持する。",
      "if_negative": "心肺疾患死亡率に一貫した上昇がなければH3は棄却またはholdとなる。"
    }
  ],
  "hypothesis_rules": [
    {
      "id": "H1",
      "accept_if": "平均寿命のRDD推定が複数の事前固定仕様で一貫して負であり、95%CIが0を下回り、かつ絶対効果量が少なくとも事前に定めた最小実質効果閾値（例：|Δlife expectancy| >= 1.0年）を満たす。",
      "reject_if": "平均寿命のRDD推定が複数仕様で0と区別できない、または正方向で一貫し、あるいは負でも効果量が閾値未満でholdに留まる。",
      "hold_if": "平均寿命の推定が負方向だが、統計的に不確実、または有意でも絶対値が最小実質効果閾値未満である。"
    },
    {
      "id": "H2",
      "accept_if": "平均寿命のRDD推定が負で、かつ複数仕様で安定しているが、絶対効果量が大きい効果の否定閾値（例：|Δlife expectancy| < 5.5年）を満たし、さらに上限信頼区間も大効果閾値を超えない。",
      "reject_if": "平均寿命のRDD推定が複数仕様で絶対値5.5年以上の大きさを示し、その大きさが安定して再現される。",
      "hold_if": "平均寿命の推定が負だが、効果量が中間域で、5.5年を明確に下回るとも上回るとも言えない、または仕様間で不安定である。"
    },
    {
      "id": "H3",
      "accept_if": "心肺疾患死亡率のRDD推定が北側で正方向に一貫し、95%CIが0を上回り、標準化効果量が事前閾値（例：0.2 SD以上）を満たす一方、平均寿命の変化はその媒介として整合的である。",
      "reject_if": "心肺疾患死亡率に一貫した正の不連続がなく、または効果量が閾値未満で、平均寿命との整合的な媒介関係も確認できない。",
      "hold_if": "心肺疾患死亡率に弱い正の傾向はあるが、統計的不確実性が大きい、または効果量が閾値未満である。"
    },
    {
      "id": "H4",
      "accept_if": "多項式次数とバンド幅を変えても、平均寿命のRDD推定の符号が負で維持され、推定値の変動が事前に定めた許容範囲（例：中心推定の±25%以内）に収まり、結論が仕様依存でない。",
      "reject_if": "次数やバンド幅の変更で符号が反転する、または推定値が許容範囲を超えて大きく変動し、結論が仕様依存である。",
      "hold_if": "符号は概ね負だが、仕様間の変動が許容範囲をやや超える、または一部仕様で不安定である。"
    }
  ],
  "rule_consistency_audit": [
    {
      "id": "H1",
      "accept_reject_overlap": "none",
      "note": "acceptは負方向かつ最小実質効果閾値超え、rejectは0近傍・正方向・またはhold域を含むため同義ではない。"
